import quoteService from '../services/quoteService';
import CustomIcon from '../components/Icons.vue';
export default {
  name: 'QuoteDetail',
  components: {
    CustomIcon
  },
  props: {
    quoteId: {
      type: String,
      required: true
    }
  },
  data() {
    return {
      quote: null,
      items: [],
      loading: true,
      error: null
    };
  },
  computed: {
    totalAmount() {
      return this.items.reduce((sum, item) => sum + parseFloat(item.price), 0);
    },
    hasRentalItems() {
      return this.items.some(item => item.is_rental && item.duration_months && item.rate_percentage);
    },
    totalMonthlyPayment() {
      return this.items.filter(item => item.is_rental && item.duration_months && item.rate_percentage).reduce((sum, item) => sum + this.calculateMonthlyPayment(item), 0);
    },
    rentalDuration() {
      const rentalItem = this.items.find(item => item.is_rental && item.duration_months);
      return rentalItem ? rentalItem.duration_months : 0;
    },
    isExpired() {
      if (!this.quote?.valid_until) return false;
      return new Date(this.quote.valid_until) < new Date();
    },
    canEdit() {
      if (!this.quote) return false;
      return !this.isExpired && this.quote.status !== 'validated' && this.quote.status !== 'refused';
    }
  },
  async mounted() {
    await this.loadQuote();
  },
  methods: {
    async loadQuote() {
      try {
        this.loading = true;
        this.error = null;
        const result = await quoteService.getById(this.quoteId);
        if (!result) {
          this.error = 'Devis introuvable';
          return;
        }
        this.quote = result;
        this.items = result.items || [];
      } catch (err) {
        this.error = 'Erreur lors du chargement: ' + err.message;
        console.error(err);
      } finally {
        this.loading = false;
      }
    },
    getStatusLabel(status) {
      const labels = {
        draft: 'Brouillon',
        pending: 'En attente',
        validated: 'Validé',
        expired: 'Expiré',
        refused: 'Refusé'
      };
      return labels[status] || status;
    },
    formatDate(dateString) {
      if (!dateString) return '-';
      const date = new Date(dateString);
      return new Intl.DateTimeFormat('fr-FR', {
        year: 'numeric',
        month: 'long',
        day: 'numeric'
      }).format(date);
    },
    formatPrice(price) {
      return new Intl.NumberFormat('fr-FR', {
        style: 'currency',
        currency: 'EUR'
      }).format(price);
    },
    calculateMonthlyPayment(item) {
      if (!item.duration_months || !item.rate_percentage) return 0;
      const price = parseFloat(item.price);
      const rate = parseFloat(item.rate_percentage) / 100;
      const months = parseInt(item.duration_months);
      const monthlyRate = rate / 12;
      const monthlyPayment = price * monthlyRate * Math.pow(1 + monthlyRate, months) / (Math.pow(1 + monthlyRate, months) - 1);
      return monthlyPayment;
    },
    async updateStatus(newStatus) {
      try {
        await quoteService.updateWithEmail(this.quoteId, {
          status: newStatus
        });
        await this.loadQuote();
      } catch (err) {
        this.error = 'Erreur lors de la mise à jour: ' + err.message;
        console.error(err);
      }
    },
    goBack() {
      this.$emit('navigate', 'quotes-list');
    },
    async downloadPdf() {
      try {
        await quoteService.generatePdf(this.quoteId);
      } catch (err) {
        this.error = 'Erreur lors de la génération du PDF: ' + err.message;
        console.error(err);
      }
    },
    editQuote() {
      this.$emit('navigate', 'edit-quote', this.quoteId);
    }
  }
};
